patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index d22379429d00..89929da90628 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -15483,6 +15483,12 @@ Value *BoUpSLP::vectorizeTree(TreeEntry *E, bool PostponedPHIs) {
       CmpInst::Predicate P0 = cast<CmpInst>(VL0)->getPredicate();
       Value *V = Builder.CreateCmp(P0, L, R);
       propagateIRFlags(V, E->Scalars, VL0);
+      // If the scalar icmp had samesign flag and the vector element type is i1,
+      // drop the samesign flag because sign is not meaningful for i1.
+      if (auto *CI = dyn_cast<ICmpInst>(VL0))
+        if (CI->hasSameSign() && isa<FixedVectorType>(V->getType()) &&
+            cast<FixedVectorType>(V->getType())->getElementType()->isIntegerTy(1))
+          cast<ICmpInst>(V)->setSameSign(false);
       // Do not cast for cmps.
       VecTy = cast<FixedVectorType>(V->getType());
       V = FinalShuffle(V, E);

